import React, {useEffect} from 'react';
import s from './UploadPreview.module.scss';

function revokeImg(file) {
    // URL.revokeObjectURL(file.preview);
    console.log(file.preview);
    setTimeout(() => {
        console.log('works');

        URL.revokeObjectURL(file.preview);
    }, 200);

}

function createImagePreview(file) {
    Object.assign(file, { preview: URL.createObjectURL(file) });

}

function UploadPreview(props) {

    // const imagePreview = (file) => (
    //     <div className={s.item__image}>
    //         <img src={URL.createObjectURL(file)} alt="Dodane zdjęcie" onLoad={revokeImg}/>
    //     </div>
    // );
    const imagePreview = (file) => (
        <div className={s.item__image}>
            <img src={createImagePreview(file)} alt="Dodane zdjęcie" onLoad={revokeImg(file)}/>
        </div>
    );

    const previews = props.files.map((file, key) => (
        <div className={s.item}>
            {file.type.indexOf("image/") !== -1 ? imagePreview(file) : null}
        </div>
    ));

    // useEffect(() => () => {
    //     // Make sure to revoke the data uris to avoid memory leaks
    //     props.files.forEach(file => URL.revokeObjectURL(file.preview));
    // }, [props.files]);

    return (
        <div>   
            {previews}
        </div>
    )
}

export default UploadPreview;
